/**
 * A CDS tranche product representing a slice of a CDS index portfolio.
 * <p>
 * A CDS tranche is a slice of credit risk from a CDS index portfolio, defined by attachment
 * and detachment points that determine the subordination level. The tranche buyer is only exposed
 * to losses between the attachment point and detachment point as a fraction of the index notional.
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * Whether the CDS tranche is buy or sell.
   * <p>
   * A value of 'Buy' implies buying protection, where the fixed coupon is paid
   * and the protection is received in the event of default.
   * A value of 'Sell' implies selling protection, where the fixed coupon is received
   * and the protection is paid in the event of default.
   */
  @PropertyDefinition(validate = "notNull")
  private final BuySell buySell;
  /**
   * The underlying CDS index.
   * <p>
   * This is the CDS index from which the tranche is derived.
   */
  @PropertyDefinition(validate = "notNull")
  private final CdsIndex underlyingIndex;
  /**
   * The attachment point, must be between 0.0 and 1.0.
   * <p>
   * This is the lower bound of the loss absorption, expressed as a fraction of the notional.
   * Losses below this point are not absorbed by this tranche.
   */
  @PropertyDefinition(validate = "ArgChecker.inRange")
  private final double attachmentPoint;
  /**
   * The detachment point, must be between 0.0 and 1.0 and greater than the attachment point.
   * <p>
   * This is the upper bound of the loss absorption, expressed as a fraction of the notional.
   * Losses above this point are not absorbed by this tranche.
   */
  @PropertyDefinition(validate = "ArgChecker.inRange")
  private final double detachmentPoint;

  //-------------------------------------------------------------------------
  @ImmutableDefaults
  private static void applyDefaults(Builder builder) {
    builder.dayCount = DayCounts.ACT_360;
    builder.paymentOnDefault = PaymentOnDefault.ACCRUED_PREMIUM;
    builder.protectionStart = ProtectionStartOfDay.BEGINNING;
    builder.stepinDateOffset = DaysAdjustment.ofCalendarDays(1);
  }

  @ImmutablePreBuild
  private static void preBuild(Builder builder) {
    if (builder.settlementDateOffset == null && builder.paymentSchedule != null) {
      builder.settlementDateOffset =
          DaysAdjustment.ofBusinessDays(3, builder.paymentSchedule.getBusinessDayAdjustment().getCalendar());
    }
    // Validate attachment and detachment points
    if (builder.attachmentPoint >= 0.0 && builder.detachmentPoint > 0.0) {
      ArgChecker.inRange(builder.attachmentPoint, 0.0, 1.0, "attachmentPoint");
      ArgChecker.inRange(builder.detachmentPoint, 0.0, 1.0, "detachmentPoint");
      ArgChecker.isTrue(builder.detachmentPoint > builder.attachmentPoint,
          "detachmentPoint must be greater than attachmentPoint");
    }
  }

